{
  "competency_groups": [
    {
      "code": "C1",
      "title": "Conceptual Foundations and Measurement",
      "description": "Equip learners with tools to understand the working of Chemistry, develop conceptual foundations, represent phenomena at macroscopic/molecular/symbolic levels, identify patterns, and apply knowledge to real-life situations.",
      "competencies": [
        "Understand nature of matter, properties, measurement, uncertainty, laws of chemical combination, Dalton's atomic theory",
        "Calculate atomic/molecular masses, mole concept, molar mass, percentage composition, stoichiometry"
      ],
      "unit_name": "Some Basic Concepts of Chemistry",
      "chapter_name": "Some Basic Concepts of Chemistry"
    },
    {
      "code": "C2",
      "title": "Atomic Structure and Quantum Models",
      "description": "Enable learners to comprehend the evolution from sub-atomic particles discovery through Bohr's model to the quantum mechanical model.",
      "competencies": [
        "Trace discoveries of sub-atomic particles and development leading to Bohr's model for Hydrogen atom"
      ],
      "unit_name": "Structure of Atom",
      "chapter_name": "Structure of Atom"
    },
    {
      "code": "C3",
      "title": "Periodic Classification and Trends",
      "description": "Enable learners to classify elements, understand the periodic law, electronic configurations, block classification (s-, p-, d-, f-), and analyze trends in properties.",
      "competencies": [
        "Apply modern periodic law and interpret the present form of Periodic Table"
      ],
      "unit_name": "Classification of Elements and Periodicity in Properties",
      "chapter_name": "Classification of Elements and Periodicity in Properties"
    },
    {
      "code": "C4",
      "title": "Chemical Bonding Theories",
      "description": "Enable learners to apply various bonding theories (Kossel-Lewis, VSEPR, Valence Bond, Molecular Orbital) and understand hybridization and hydrogen bonding.",
      "competencies": [
        "Analyze bond parameters and predict molecular geometry using VSEPR theory"
      ],
      "unit_name": "Chemical Bonding and Molecular Structure",
      "chapter_name": "Chemical Bonding and Molecular Structure"
    },
    {
      "code": "C5",
      "title": "Thermodynamics and Spontaneity",
      "description": "Enable learners to measure enthalpy changes, understand spontaneity, Gibbs energy change, and equilibrium conditions.",
      "competencies": [
        "Calculate ∆U and ∆H using calorimetry"
      ],
      "unit_name": "Thermodynamics",
      "chapter_name": "Chemical Thermodynamics"
    },
    {
      "code": "C6",
      "title": "Equilibrium Principles",
      "description": "Enable learners to analyze dynamic equilibrium in physical and chemical processes, apply the law of chemical equilibrium, and understand factors affecting equilibria including ionic equilibrium.",
      "competencies": [
        "Relate Equilibrium Constant K, Reaction Quotient Q, and Gibbs Energy G"
      ],
      "unit_name": "Equilibrium",
      "chapter_name": "Equilibrium"
    },
    {
      "code": "C7",
      "title": "Redox Processes",
      "description": "Enable learners to identify oxidation-reduction reactions through classical ideas, electron transfer, and oxidation numbers.",
      "competencies": [
        "Analyze redox reactions in terms of electrode processes"
      ],
      "unit_name": "Redox Reactions",
      "chapter_name": "Redox Reactions"
    },
    {
      "code": "C8",
      "title": "Organic Chemistry Fundamentals and Mechanisms",
      "description": "Enable learners to represent organic compounds structurally, classify them, apply IUPAC nomenclature, understand isomerism, reaction mechanisms, purification methods, and analysis techniques.",
      "competencies": [
        "Apply fundamental concepts in Organic Reaction Mechanism"
      ],
      "unit_name": "Organic Chemistry: Some basic Principles and Techniques",
      "chapter_name": "Some basic Principles and Techniques"
    },
    {
      "code": "C9",
      "title": "Hydrocarbon Classification and Properties",
      "description": "Enable learners to classify hydrocarbons, understand properties of alkanes, alkenes, alkynes, aromatic compounds, and assess carcinogenicity/toxicity.",
      "competencies": [
        "Differentiate between various classes of hydrocarbons"
      ],
      "unit_name": "Hydrocarbons",
      "chapter_name": "Hydrocarbons"
    },
    {
      "code": "C10",
      "title": "Solutions and Colligative Properties",
      "description": "Enable learners to express concentration, understand solubility, vapor pressure of solutions, ideal/non-ideal behavior, and determine molar mass using colligative properties.",
      "competencies": [
        "Apply concepts of abnormal molecular masses"
      ],
      "unit_name": "Solutions",
      "chapter_name": "Solutions"
    },
    {
      "code": "C11",
      "title": "Electrochemistry and Energy Conversion",
      "description": "Enable learners to understand electrochemical cells, Nernst equation, conductance, electrolysis, batteries, fuel cells, and corrosion.",
      "competencies": [
        "Analyze galvanic cells and apply the Nernst Equation"
      ],
      "unit_name": "Electrochemistry",
      "chapter_name": "Electrochemistry"
    },
    {
      "code": "C12",
      "title": "Chemical Kinetics and Reaction Rates",
      "description": "Enable learners to analyze factors influencing reaction rates, integrated rate equations, temperature dependence, and collision theory.",
      "competencies": [
        "Interpret the Temperature Dependence of the rate of a reaction"
      ],
      "unit_name": "Chemical Kinetics",
      "chapter_name": "Chemical Kinetics"
    },
    {
      "code": "C13",
      "title": "d- and f-Block Elements Chemistry",
      "description": "Enable learners to understand electronic configurations, general properties of transition elements, lanthanoids/actinoids, and applications.",
      "competencies": [
        "Correlate position in Periodic Table with electronic configuration"
      ],
      "unit_name": "d-and f-Block Elements",
      "chapter_name": "d -and f -Block Elements"
    },
    {
      "code": "C14",
      "title": "Coordination Chemistry and Bonding",
      "description": "Enable learners to apply Werner's theory, understand nomenclature, isomerism, bonding in coordination compounds (including metal carbonyls), and applications.",
      "competencies": [
        "Apply IUPAC nomenclature for Coordination Compounds"
      ],
      "unit_name": "Coordination Compounds",
      "chapter_name": "Coordination Compounds"
    },
    {
      "code": "C15",
      "title": "Organic Halogen Derivatives and Functional Groups",
      "description": "Enable learners to classify haloalkanes/haloarenes, understand preparation methods, physical/chemical properties, and reactions of alcohols, phenols, ethers.",
      "competencies": [
        "Analyze the nature of C–X bond in Haloalkanes"
      ],
      "unit_name": "Haloalkanes and Haloarenes",
      "chapter_name": "Haloalkanes and Haloarenes"
    },
    {
      "code": "C16",
      "title": "Carbonyl Compounds Chemistry",
      "description": "Enable learners to understand nomenclature, preparation, physical properties, chemical reactions, and uses of aldehydes, ketones, and carboxylic acids.",
      "competencies": [
        "Differentiate between Aldehydic and Ketonic groups"
      ],
      "unit_name": "Aldehydes, Ketones and Carboxylic Acids",
      "chapter_name": "Aldehydes, Ketones and Carboxylic Acids"
    },
    {
      "code": "C17",
      "title": "Amines and Diazonium Salts Synthesis",
      "description": "Enable learners to classify amines, understand preparation methods, physical/chemical properties, and the importance of diazonium salts in synthesis.",
      "competencies": [
        "Apply chemical reactions for synthesis of aromatic compounds using Diazonium Salts"
      ],
      "unit_name": "Amines",
      "chapter_name": "Amines"
    },
    {
      "code": "C18",
      "title": "Biomolecules and Biochemistry Interface",
      "description": "Enable learners to understand the structure, classification, and functions of carbohydrates, proteins, enzymes, vitamins, nucleic acids, and hormones.",
      "competencies": [
        "Identify key biomolecules including Enzymes and Hormones"
      ],
      "unit_name": "Biomolecules",
      "chapter_name": "Biomolecules"
    },
    {
      "code": "C19",
      "title": "Surface Chemistry and Colloids",
      "description": "Enable learners to distinguish between true solutions, colloids, and suspensions; understand adsorption (physisorption/chemisorption), lyophilic/lyophobic properties, coagulation, and emulsions.",
      "competencies": [
        "Analyze the role of emulsifying agents in stabilizing emulsions"
      ],
      "unit_name": "Surface Chemistry",
      "chapter_name": "Surface Chemistry"
    },
    {
      "code": "C20",
      "title": "Isolation and Extraction Principles",
      "description": "Enable learners to understand principles of extraction, concentration methods (oxidation/reduction), electrolytic refining, and polymerization concepts.",
      "competencies": [
        "Apply general principles for isolation of elements"
      ],
      "unit_name": "General Principles and Processes of Isolation of Elements",
      "chapter_name": "General Principles and Processes of Isolation of Elements"
    },
    {
      "code": "C21",
      "title": "Chemistry in Everyday Life",
      "description": "Enable learners to apprise themselves of chemicals used in medicines (analgesics, antibiotics, etc.) and food preservatives/sweeteners.",
      "competencies": [
        "Identify applications of antiseptics, disinfectants, and antimicrobials"
      ],
      "unit_name": "Chemistry in Everyday life",
      "chapter_name": "Chemistry in Everyday life"
    },
    {
      "code": "C22",
      "title": "Laboratory Techniques and Safety",
      "description": "Enable learners to perform basic laboratory techniques (cutting, bending glass), characterization/purification of substances, pH determination, and qualitative/quantitative analysis safely.",
      "competencies": [
        "Execute micro-chemical methods for practical experiments"
      ],
      "unit_name": "Basic Laboratory Techniques",
      "chapter_name": "Characterization and Purification of Chemical Substances"
    },
    {
      "code": "C23",
      "title": "Scientific Inquiry and Problem Solving",
      "description": "Enable learners to contribute to frontier research areas, inculcate problem-solving skills, integrate life skills/values, and conduct scientific investigations/projects.",
      "competencies": [
        "Design and execute investigatory projects involving laboratory testing"
      ],
      "unit_name": "Project Work",
      "chapter_name": "Scientific Investigations"
    }
  ]
}
